package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    void testValidate() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n", null, null, false, false);

        Method validateMethod = CSVFormat.class.getDeclaredMethod("validate");
        validateMethod.setAccessible(true);
        assertThrows(IllegalArgumentException.class, () -> validateMethod.invoke(csvFormat));

        csvFormat = new CSVFormat(',', '"', null, null, '\\', false, true, "\r\n", null, null, false, false);
        assertThrows(IllegalArgumentException.class, () -> validateMethod.invoke(csvFormat));

        csvFormat = new CSVFormat(',', '"', null, '#', null, false, true, "\r\n", null, null, false, false);
        assertThrows(IllegalArgumentException.class, () -> validateMethod.invoke(csvFormat));

        csvFormat = new CSVFormat(',', '#', null, '#', null, false, true, "\r\n", null, null, false, false);
        assertThrows(IllegalArgumentException.class, () -> validateMethod.invoke(csvFormat));

        csvFormat = new CSVFormat(',', null, QuoteMode.NONE, null, null, false, true, "\r\n", null, null, false, false);
        assertThrows(IllegalArgumentException.class, () -> validateMethod.invoke(csvFormat));
    }
}
